const raw = ($input.first().json.chatInput || "").trim();
const text = raw.toLowerCase();

// Greeting guard (so "Hola" doesn't trigger retrieval)
const isGreeting = /^(hola|buenas|hello|hi|hey|saludos|buenos dias|buenas tardes|buenas noches)\b/i.test(raw);

// Detect norm IDs like "nicsp 02", "norma 3", "la 3ra", etc.
const match =
  text.match(/nicsp[\s-]*0*([1-9]\d?)/i) ||
  text.match(/norma[\s-]*0*([1-9]\d?)/i) ||
  text.match(/\bla[\s-]*0*([1-9]\d?)\b/i) ||
  text.match(/\b([1-9]\d?)(era|ra|da|ta)\b/i);

let normaId = null;
if (match) {
  const n = parseInt(match[1], 10);
  if (n >= 1 && n <= 99) {
    normaId = `NICSP-${String(n).padStart(2, "0")}`;
  }
}

// Determine doc_set based on keywords. If a specific norm is found, doc_set is NICSP.
let docSet = null;
if (normaId) {
  docSet = "NICSP";
} else {
  const txt = text.toLowerCase();
  if (/(nicsp|norma nicsp)/.test(txt)) {
    docSet = "NICSP";
  } else if (/(digecog|erir|contabilidad gubernamental|ministerio de hacienda|direcci\u00f3n general de contabilidad|dige)/.test(txt)) {
    docSet = "DIGECOG";
  }
}

// Coreference -> inherit last_norma_id/doc_set from state
const coref = /\b(esta norma|esa norma|la norma|que dice esta norma|qué dice esta norma|que dice la norma|qué dice la norma|que dice esa norma|qué dice esa norma|sobre eso|eso|lo anterior|la anterior|esa nicsp|esta nicsp)\b/i;
if (!normaId && coref.test(raw) && $json.last_norma_id) {
  normaId = $json.last_norma_id;
  docSet = $json.last_doc_set || "NICSP";
}

return [{ json: { ...$json, norma_id: normaId, doc_set: docSet, is_greeting: isGreeting } }];

let q = ($json.chatInput || "").trim();

// 1) Mantén la pregunta original SIEMPRE.
// 2) Solo añade “contexto” sin cambiar la intención del usuario.

if ($json.doc_set === 'NICSP') {
  // Si detectó norma específica, NO reescribas a resumen.
  // Solo ancla la consulta a esa norma, manteniendo la pregunta.
  if ($json.norma_id) {
    q = `${q} (norma: ${$json.norma_id})`;
  } else {
    // NICSP sin norma específica: solo prefijo suave
    q = `NICSP: ${q}`;
  }
} else if ($json.doc_set === 'DIGECOG') {
  q = `DIGECOG: ${q}`;
}

return [{ json: { ...$json, rag_query: q } }];

