const base = $node["Build Query"].json || {};
const rows = items.map(i => i.json);

// filtra basura/vacíos
const cleaned = rows.filter(r => ((r.text ?? "") + "").trim().length > 0);

const rag_context = cleaned
  .map((r, idx) => {
    const m = r.metadata || {};
    const text = ((r.text ?? "") + "").trim();

    return [
      "Fragmento " + (idx + 1),
      "chunk_id: " + (r.chunk_id || m.chunk_id || ""),
      "doc_set: " + (m.doc_set || ""),
      "norma_id: " + (m.norma_id || ""),
      "sección: " + (m.seccion || ""),
      "subsección: " + (m.subseccion || ""),
      "similaridad: " + (r.similarity ?? ""),
      "texto:\n" + text
    ].join("\n");
  })
  .join("\n\n---\n\n");

return [{
  json: {
    ...base,          // <-- aquí vuelven rag_query, doc_set, norma_id, chatInput
    rag_rows: cleaned,
    rag_context
  }
}];

const msg = ($json.message || {});
const chatId = msg.chat?.id;
const fromId = msg.from?.id;

const channel = 'telegram';
const user_ref = fromId ? String(fromId) : 'unknown';
const thread_ref = chatId ? String(chatId) : user_ref;
const session_id = `${channel}:${user_ref}:${thread_ref}`;

const chatInput = (msg.text || '').trim();

return [{ json: { ...$json, channel, user_ref, thread_ref, session_id, chatInput } }];

const state = $input.first().json || {};
const base = $node["Normalize Event"].json || {};
return [{ json: { ...base, last_norma_id: (state.last_norma_id ?? null), last_doc_set: (state.last_doc_set ?? null) } }];
